function countPalindromes(s) {
  let count = 0;
  for (let i = 0; i < s.length; i++) {
    for (let d = 0; d <= 1; d++) {
      let [l, r] = [i, i + d];
      while (l >= 0 && r < s.length && s[l] === s[r]) {
        count++; l--; r++;
      }
    }
  }
  return count;
}
