class Main {
    static class ListNode { int val; ListNode next; ListNode(int v){val=v;} }

    // #206 完整反轉
    static ListNode reverse(ListNode head) {
        ListNode prev = null, cur = head;
        while (cur != null) {
            ListNode next = cur.next;
            cur.next = prev; prev = cur; cur = next;
        }
        return prev;
    }

    // #92 部分反轉 [left, right]
    static ListNode reverseBetween(ListNode head, int left, int right) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        ListNode prev = dummy;
        for (int i = 1; i < left; i++) prev = prev.next;
        ListNode cur = prev.next;
        for (int i = 0; i < right - left; i++) {
            ListNode next = cur.next;
            cur.next = next.next;
            next.next = prev.next;
            prev.next = next;
        }
        return dummy.next;
    }

    static String str(ListNode n) {
        StringBuilder sb = new StringBuilder();
        while (n!=null){sb.append(n.val);if(n.next!=null)sb.append("->");n=n.next;}
        return sb.toString();
    }
    static ListNode make(int...v){ListNode d=new ListNode(0),c=d;for(int x:v){c.next=new ListNode(x);c=c.next;}return d.next;}

    public static void main(String[] args) {
        System.out.println(str(reverse(make(1,2,3,4,5))));
        System.out.println(str(reverseBetween(make(1,2,3,4,5), 2, 4)));
    }
}

