int binary_search(int arr[], int n, int target) {
    int l = 0, r = n - 1;
    while (l <= r) {
        int mid = (l + r) / 2;
        if (arr[mid] == target) return mid;
        else if (arr[mid] < target) l = mid + 1;
        else r = mid - 1;
    }
    return -1;
}
int main() {
    int a[] = {1,3,5,7,9,11,13,15};
    printf("%d\n", binary_search(a, 8, 7));   // 3
    printf("%d\n", binary_search(a, 8, 6));   // -1
}

