struct Node {
    int val;
    Node* next;
    Node(int v) : val(v), next(nullptr) {}
};

class LinkedList {
    Node* head = nullptr;
public:
    void push_front(int v) {
        Node* n = new Node(v);
        n->next = head;
        head = n;
    }
    void push_back(int v) {
        Node* n = new Node(v);
        if (!head) { head = n; return; }
        Node* cur = head;
        while (cur->next) cur = cur->next;
        cur->next = n;
    }
    void print() const {
        for (Node* c = head; c; c = c->next)
            cout << c->val << (c->next ? " -> " : "
");
    }
    ~LinkedList() {
        while (head) { Node* t = head->next; delete head; head = t; }
    }
};

int main() {
    LinkedList list;
    for (int i : {3, 1, 4, 1, 5}) list.push_back(i);
    list.push_front(0);
    list.print();
    return 0;
}

