using namespace std;

typedef pair<int,int> pii;

vector<int> dijkstra(int n, vector<vector<pii>>& adj, int src) {
    vector<int> dist(n, INT_MAX);
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    dist[src] = 0;
    pq.push({0, src});
    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();
        if (d > dist[u]) continue;
        for (auto [w, v] : adj[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}

int main() {
    int n = 5;
    vector<vector<pii>> adj(n);
    // {weight, to}
    adj[0].push_back({4,1}); adj[0].push_back({1,2});
    adj[1].push_back({1,3}); adj[2].push_back({2,1});
    adj[2].push_back({5,3}); adj[3].push_back({3,4});

    auto dist = dijkstra(n, adj, 0);
    for (int i = 0; i < n; i++)
        cout << "0 到 " << i << "：" << dist[i] << "
";
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int rob(vector<int>& nums) {
    int prev2=0, prev1=0;
    for (int n : nums) {
        int cur = max(prev1, prev2+n);
        prev2=prev1; prev1=cur;
    }
    return prev1;
}

int robCircular(vector<int>& nums) {
    int n = nums.size();
    if (n==1) return nums[0];
    auto robRange = [&](int l, int r) {
        int p2=0,p1=0;
        for (int i=l;i<=r;i++){int c=max(p1,p2+nums[i]);p2=p1;p1=c;}
        return p1;
    };
    return max(robRange(0,n-2), robRange(1,n-1));
}

int main() {
    vector<int> a={2,7,9,3,1}, b={2,3,2}, c={1,2,3,1};
    cout << rob(a) << "\n";           // 12
    cout << robCircular(b) << "\n";   // 3
    cout << robCircular(c) << "\n";   // 4
    return 0;
}

