struct TreeNode{int val;TreeNode*left,*right;TreeNode(int v):val(v),left(nullptr),right(nullptr){}};
pair<int,int> dfs(TreeNode* node) {
    if (!node) return {0,0};
    auto [lr,lnr]=dfs(node->left);
    auto [rr,rnr]=dfs(node->right);
    int rob=node->val+lnr+rnr;
    int no_rob=max(lr,lnr)+max(rr,rnr);
    return {rob,no_rob};
}
int robTree(TreeNode* root){auto[r,nr]=dfs(root);return max(r,nr);}
int main(){
    TreeNode* r=new TreeNode(3);
    r->left=new TreeNode(2);r->right=new TreeNode(3);
    r->left->right=new TreeNode(3);r->right->right=new TreeNode(1);
    cout<<robTree(r)<<"\n"; // 7
}

