class Program {
    static int BinarySearch(int[] arr, int target) {
        int l = 0, r = arr.Length - 1;
        while (l <= r) {
            int mid = (l + r) / 2;
            if (arr[mid] == target) return mid;
            else if (arr[mid] < target) l = mid + 1;
            else r = mid - 1;
        }
        return -1;
    }

    static void Main() {
        int[] nums = {64, 34, 25, 12, 22, 11, 90};
        int[] sorted = nums.OrderBy(x => x).ToArray();
