using System;
using System.Collections.Generic;

class Program {
    static int CoinChange(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Array.Fill(dp, amount + 1);
        dp[0] = 0;
        for (int i = 1; i <= amount; i++)
            foreach (int c in coins)
                if (c <= i)
                    dp[i] = Math.Min(dp[i], dp[i - c] + 1);
        return dp[amount] > amount ? -1 : dp[amount];
    }

    static int[] CoinChangeCoins(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        int[] last = new int[amount + 1];
        Array.Fill(dp, amount + 1);
        dp[0] = 0;
        for (int i = 1; i <= amount; i++)
            foreach (int c in coins)
                if (c <= i && dp[i-c]+1 < dp[i]) {
                    dp[i] = dp[i-c] + 1; last[i] = c;
                }
        var result = new List<int>();
        while (amount > 0) { result.Add(last[amount]); amount -= last[amount]; }
        return result.ToArray();
    }

    static void Main() {
        int[] coins = {1, 5, 10, 25};
        Console.WriteLine($"41元最少硬幣：{CoinChange(coins, 41)}枚");
        Console.WriteLine("組合：" + string.Join("+", CoinChangeCoins(coins, 41)));
    }
}

using System;
using System.Collections.Generic;
using System.Linq;

class Program {
    // 兩數之和（HashMap O(n)）
    static int[] TwoSum(int[] nums, int target) {
        var map = new Dictionary<int, int>();
        for (int i = 0; i < nums.Length; i++) {
            int complement = target - nums[i];
            if (map.ContainsKey(complement))
                return new[] { map[complement], i };
            map[nums[i]] = i;
        }
        return Array.Empty<int>();
    }

    // 子陣列總和等於 k 的個數（前綴和）
    static int SubarraySum(int[] nums, int k) {
        var prefixCount = new Dictionary<int, int> {{ 0, 1 }};
        int sum = 0, count = 0;
        foreach (int n in nums) {
            sum += n;
            count += prefixCount.GetValueOrDefault(sum - k, 0);
            prefixCount[sum] = prefixCount.GetValueOrDefault(sum, 0) + 1;
        }
        return count;
    }

    static void Main() {
        Console.WriteLine(string.Join(",", TwoSum(new[]{2,7,11,15}, 9))); // 0,1
        Console.WriteLine(SubarraySum(new[]{1,1,1}, 2));                  // 2
        Console.WriteLine(SubarraySum(new[]{1,2,3}, 3));                  // 2
    }
}

using System;

class Program {
    static int UniquePaths(int m, int n) {
        int[] dp = new int[n];
        Array.Fill(dp, 1);
        for (int i=1;i<m;i++)
            for (int j=1;j<n;j++)
                dp[j]+=dp[j-1];
        return dp[n-1];
    }

    static int MinPathSum(int[][] grid) {
        int m=grid.Length, n=grid[0].Length;
        for (int i=0;i<m;i++)
            for (int j=0;j<n;j++) {
                if (i==0&&j==0) continue;
                int up   = i>0 ? grid[i-1][j] : int.MaxValue;
                int left = j>0 ? grid[i][j-1] : int.MaxValue;
                grid[i][j] += Math.Min(up, left);
            }
        return grid[m-1][n-1];
    }

    static void Main() {
        Console.WriteLine(UniquePaths(3,7));  // 28
        var grid = new[]{new[]{1,3,1},new[]{1,5,1},new[]{4,2,1}};
        Console.WriteLine(MinPathSum(grid));  // 7
    }
}

