class Program {
    static bool IsValid(string s) {
        var stk = new Stack<char>();
        var map = new Dictionary<char,char>{{')','('},{']','['},{'}','{'}};
        foreach (char c in s) {
            if ("([{".Contains(c)) stk.Push(c);
            else if (!map.ContainsKey(c)||stk.Count==0||stk.Pop()!=map[c]) return false;
        }
        return stk.Count==0;
    }

    class Trie {
        Dictionary<char,Trie> ch=new();
        bool end;
        public void Insert(string w){var n=this;foreach(var c in w){if(!n.ch.ContainsKey(c))n.ch[c]=new Trie();n=n.ch[c];}n.end=true;}
        public bool Search(string w){var n=this;foreach(var c in w){if(!n.ch.ContainsKey(c))return false;n=n.ch[c];}return n.end;}
        public bool StartsWith(string p){var n=this;foreach(var c in p){if(!n.ch.ContainsKey(c))return false;n=n.ch[c];}return true;}
    }

    static void Main() {
        Console.WriteLine(IsValid("()[]{}"));  // True
        Console.WriteLine(IsValid("([)]"));    // False
        var trie=new Trie();
        foreach(var w in new[]{"apple","app","apply"}) trie.Insert(w);
        Console.WriteLine(trie.Search("apple"));   // True
        Console.WriteLine(trie.StartsWith("app")); // True
    }
}

