  WriteLn('P2 = ' + P2.ToString);
  WriteLn(Format('Distance = %.2f', [P1.Distance(P2)]));
  ReadLn;
end.

program FibDemo;
{$APPTYPE CONSOLE}
uses SysUtils;

function Fibonacci(n: Integer): TArray<Int64>;
var
  i: Integer;
begin
  SetLength(Result, n);
  if n > 0 then Result[0] := 0;
  if n > 1 then Result[1] := 1;
  for i := 2 to n - 1 do
    Result[i] := Result[i-1] + Result[i-2];
end;

var
  seq: TArray<Int64>;
  i: Integer;
begin
  seq := Fibonacci(15);
  Write('前15項：');
  for i := 0 to High(seq) do
    Write(seq[i], ' ');
  WriteLn;
  WriteLn('第20項：', Fibonacci(21)[20]);
  ReadLn;
end.

program SortDemo;
{$APPTYPE CONSOLE}

procedure BubbleSort(var arr: array of Integer);
var
  i, j, tmp: Integer;
begin
  for i := 0 to High(arr) - 1 do
    for j := 0 to High(arr) - i - 1 do
      if arr[j] > arr[j+1] then
      begin
        tmp := arr[j];
        arr[j] := arr[j+1];
        arr[j+1] := tmp;
      end;
end;

procedure PrintArr(const arr: array of Integer);
var i: Integer;
begin
  for i := 0 to High(arr) do
    Write(arr[i], ' ');
  WriteLn;
end;

var
  data: array of Integer;
begin
  data := TArray<Integer>.Create(64, 34, 25, 12, 22, 11, 90);
  Write('排序前：'); PrintArr(data);
  BubbleSort(data);
  Write('排序後：'); PrintArr(data);
  ReadLn;
end.

