uses Math;

function IsPrime(n: Integer): Boolean;
var i: Integer;
begin
  if n < 2 then Exit(False);
  for i := 2 to Trunc(Sqrt(n)) do
    if n mod i = 0 then Exit(False);
  Result := True;
end;

var n: Integer;
begin
  for n in [1, 2, 7, 10, 13, 25] do
    WriteLn(n, ': ', IfThen(IsPrime(n), '質數', '合數'));
  ReadLn;
end.

