program StringDemo;
{$APPTYPE CONSOLE}
uses SysUtils;

function IsPalindrome(const s: string): Boolean;
var
  lo, hi: Integer;
  lower: string;
begin
  lower := LowerCase(s);
  lo := 1; hi := Length(lower);
  while lo < hi do
  begin
    if lower[lo] <> lower[hi] then Exit(False);
    Inc(lo); Dec(hi);
  end;
  Result := True;
end;

var
  words: array of string;
  w: string;
begin
  words := TArray<string>.Create('racecar','hello','level','Delphi');
  for w in words do
    WriteLn(Format('"%s" %s迴文', [w, IfThen(IsPalindrome(w),'是','不是')]));

  WriteLn('反轉：', ReverseString('Hello Delphi'));
  WriteLn('大寫：', UpperCase('delphi rocks'));
  ReadLn;
end.

program QuickSortDemo;
{$APPTYPE CONSOLE}

procedure QuickSort(var arr: array of Integer; Lo, Hi: Integer);
var
  pivot, tmp, i, j: Integer;
begin
  if Lo >= Hi then Exit;
  pivot := arr[(Lo + Hi) div 2];
  i := Lo; j := Hi;
  while i <= j do
  begin
    while arr[i] < pivot do Inc(i);
    while arr[j] > pivot do Dec(j);
    if i <= j then
    begin
      tmp := arr[i]; arr[i] := arr[j]; arr[j] := tmp;
      Inc(i); Dec(j);
    end;
  end;
  QuickSort(arr, Lo, j);
  QuickSort(arr, i, Hi);
end;

var
  data: array of Integer;
  i: Integer;
begin
  data := TArray<Integer>.Create(10, 7, 8, 9, 1, 5, 3, 6);
  Write('排序前：');
  for i in data do Write(i, ' ');
  WriteLn;
  QuickSort(data, 0, High(data));
  Write('排序後：');
  for i in data do Write(i, ' ');
  WriteLn;
  ReadLn;
end.
